private:
    AscendC::TPipe pipe_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> bufX_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> bufH_;
    AscendC::TBuf<AscendC::TPosition::VECCALC> bufPreA_;
